import * as effector from 'effector';
import * as url from 'url';
import * as zod from 'zod';

interface File {
    type: 'file';
    path: string;
}
interface Folder {
    type: 'folder';
    path: string;
    children: Array<File | Folder>;
}
type BaseRuleOptions = Record<string, unknown>;
interface Rule<Context = unknown, RuleOptions extends BaseRuleOptions = BaseRuleOptions, RuleName extends string | number | symbol = string> {
    /** Short code name for the rule. */
    name: RuleName;
    check: (this: Context, root: Folder, ruleOptions: RuleOptions) => RuleResult | Promise<RuleResult>;
}
interface RuleResult {
    diagnostics: Array<PartialDiagnostic>;
}
interface PartialDiagnostic {
    message: string;
    fixes?: Array<Fix>;
    location: {
        /** Absolute path to a folder or a file that contains the issue. */
        path: string;
        line?: number;
        column?: number;
    };
}
type Fix = {
    type: 'rename';
    path: string;
    newName: string;
} | {
    type: 'create-file';
    path: string;
    content: string;
} | {
    type: 'create-folder';
    path: string;
} | {
    type: 'delete';
    path: string;
} | {
    type: 'modify-file';
    path: string;
    content: string;
};
type Config<Rules extends Array<Rule>> = Array<ConfigObject<Rules> | Plugin<unknown, Rules> | GlobalIgnore>;
type Severity = 'off' | 'warn' | 'error';
/**
 * Extracts a union of rule names from a given tuple of `Rule` objects.
 *
 * @example
 * type Context = unknown
 * type Options = BaseRuleOptions
 * type Result = RuleNames<[Rule<Context, Options, 'foo'>, Rule<Context, Options, 'bar'>]>
 * // Result is 'foo' | 'bar'
 */
type RuleNames<Rules extends Array<Rule>> = Rules[number]['name'];
type LookUpByName<Union, Name> = Union extends {
    name: Name;
} ? Union : never;
/**
 * Looks up a rule in a tuple of rules by name and then extracts that rule's options type.
 *
 * @example
 * type Context = unknown
 * type Rules = [Rule<Context, { foo: string }, 'foo'>, Rule<Context, { bar: number }, 'bar'>]
 * type Result = OptionsForRule<Rules, 'foo'>
 * // Result is { foo: string }
 */
type OptionsForRule<Rules extends Array<Rule>, RuleName extends RuleNames<Rules>> = LookUpByName<Rules[number], RuleName> extends Rule<unknown, infer Options> ? Options : never;
interface ConfigObject<Rules extends Array<Rule>> {
    /** Globs of files to check. */
    files?: Array<string>;
    /** Globs of files to ignore. */
    ignores?: Array<string>;
    /** Severity of rules and individual rule options. */
    rules: {
        [key in RuleNames<Rules>]?: Severity | [Severity, OptionsForRule<Rules, key>];
    };
}
type GlobalIgnore = {
    ignores: Array<string>;
};
interface Plugin<Context = unknown, Rules extends Array<Rule<Context>> = Array<Rule>> {
    meta: {
        name: string;
        version: string;
    };
    ruleDefinitions: Rules;
}

declare function processConfiguration(rawConfig: Config<Array<Rule>>, configLocationFolder: string | null): (zod.objectOutputType<{
    ignores: zod.ZodArray<zod.ZodString, "many">;
}, zod.ZodTypeAny, "passthrough"> | {
    rules: Record<string, "off" | "warn" | "error" | ["warn" | "error", zod.objectOutputType<{}, zod.ZodTypeAny, "passthrough">]>;
    files?: string[] | undefined;
    ignores?: string[] | undefined;
} | {
    ruleDefinitions: {
        name: string;
        check: (...args: unknown[]) => {
            diagnostics: any[];
        } | Promise<{
            diagnostics: any[];
        }>;
    }[];
    meta: {
        name: string;
        version: string;
    };
})[];

declare function getRuleDescriptionUrl(ruleName: string): url.URL;
declare const linter: {
    run: (path: string) => Promise<{
        ruleName: string;
        getRuleDescriptionUrl: typeof getRuleDescriptionUrl;
        severity: "warn" | "error";
        message: string;
        fixes?: Array<Fix>;
        location: {
            path: string;
            line?: number;
            column?: number;
        };
    }[]>;
    watch: (path: string) => Promise<readonly [effector.Event<{
        ruleName: string;
        getRuleDescriptionUrl: typeof getRuleDescriptionUrl;
        severity: "warn" | "error";
        message: string;
        fixes?: Array<Fix>;
        location: {
            path: string;
            line?: number;
            column?: number;
        };
    }[]>, () => Promise<void>]>;
};
declare function defineConfig<Rules extends Array<Rule> = Array<Rule>>(config: Config<Rules>): Config<Rules>;

export { defineConfig, linter, processConfiguration };
